"""Severity policy definitions for vulnerability management.

Defines severity levels and thresholds used across the scanning pipeline.
"""

from enum import IntEnum
from typing import Set


class Severity(IntEnum):
    """Vulnerability severity levels, ordered by criticality."""
    CRITICAL = 4
    HIGH = 3
    MEDIUM = 2
    LOW = 1
    UNKNOWN = 0

    @classmethod
    def from_string(cls, value: str) -> 'Severity':
        """Parse severity from string value."""
        try:
            return cls[value.upper()]
        except KeyError:
            return cls.UNKNOWN


class SeverityPolicy:
    """Defines which severity levels should block deployment."""

    def __init__(self, blocking_severities: Set[Severity] = None):
        self.blocking_severities = blocking_severities or {Severity.CRITICAL, Severity.HIGH}

    def is_blocking(self, severity: Severity) -> bool:
        """Check if a given severity level should block deployment."""
        return severity in self.blocking_severities

    def get_blocking_levels(self) -> Set[str]:
        """Return human-readable set of blocking severity names."""
        return {s.name for s in self.blocking_severities}

